import React, { useState } from 'react';
import './Hero.css';

const API = process.env.REACT_APP_API_URL || 'http://localhost:5000';

const CAR_TYPES = ['4 chỗ', '7 chỗ', 'Limousine'];
const SERVICE_OPTIONS = ['Đi nội thành', 'Đưa đón sân bay', 'Liên tỉnh', 'Thuê xe theo giờ', 'Đưa đón doanh nghiệp', 'Xe cưới', 'Chuyến riêng'];

export default function Hero({ showToast }) {
  const [form, setForm] = useState({ pickup: '', destination: '', datetime: '', carType: '4 chỗ', service: 'Đi nội thành', name: '', phone: '', note: '' });
  const [loading, setLoading] = useState(false);
  const [quoteNote, setQuoteNote] = useState(null);

  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const getServiceResponse = service => {
    if (service === 'Liên tỉnh' || service === 'Thuê xe theo giờ') {
      return { type: 'error', message: 'Không đủ xe trống cho dịch vụ này.' };
    }
    if (service === 'Đưa đón doanh nghiệp' || service === 'Xe cưới') {
      return { type: 'success', message: 'Vui lòng liên hệ qua hotline hoặc Zalo để được tư vấn chi tiết.' };
    }
    return { type: 'success', message: 'Chúng tôi đã nhận được thông tin của bạn và sẽ liên hệ trong thời gian từ 3-5 phút.' };
  };

  const handleEstimate = () => {
    if (!form.pickup || !form.destination) return showToast('Nhập điểm đón và điểm đến để nhận báo giá', 'error');
    const serviceResponse = getServiceResponse(form.service);
    setQuoteNote(serviceResponse.message);
  };

  const handleBook = async e => {
    e.preventDefault();
    if (!form.pickup || !form.destination || !form.name || !form.phone)
      return showToast('Vui lòng điền đầy đủ thông tin bắt buộc', 'error');
    const serviceResponse = getServiceResponse(form.service);
    setLoading(true);
    try {
      const res = await fetch(`${API}/api/booking`, {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(form),
      });
      const data = await res.json();
      showToast(data.message || serviceResponse.message, data.success ? 'success' : 'error');
      if (data.success) setForm({ pickup: '', destination: '', datetime: '', carType: '4 chỗ', service: 'Đi nội thành', name: '', phone: '', note: '' });
    } catch {
      showToast(serviceResponse.message, serviceResponse.type);
    }
    finally { setLoading(false); }
  };

  return (
    <section id="hero" className="hero">
      <div className="hero__bg" aria-hidden="true">
        <div className="hero__overlay" />
      </div>

      <div className="container hero__inner">
        <div className="hero__copy">
          <div className="hero__badge"> Phục vụ 24/7 — Toàn tỉnh Tây Ninh</div>
          <h1 className="hero__title">
            Đặt xe nhanh<br />
            <span className="hero__title-accent">an toàn · đúng giờ</span>
          </h1>
          <p className="hero__sub">
            Taxi Tây Ninh — hãng xe uy tín với đội xe đời mới, tài xế chuyên nghiệp,
            cung cấp báo giá nhanh theo tuyến đường và nhu cầu của quý khách.
          </p>

          {/* Hotline CTA */}
          <div className="hero__hotline">
            <a href="tel:19001234" className="btn btn-danger hero__call">
               Gọi ngay: <strong>0329.537.532</strong>
            </a>
            <span className="hero__hotline-note">· Có xe trong vài phút</span>
          </div>

          {/* App download */}
          <div className="hero__apps">
            <a href="#" className="hero__app-btn" aria-label="Google Play">
              <span><img 
    src="https://www.image2url.com/r2/default/images/1782297065186-fc90e51e-560a-44fa-baef-75305d3c8bd7.png" 
    alt="Google Play Logo"
    style={{ height: '50px', width: 'auto', marginRight: '5px' }} 
  /></span> Google Play
            </a>
            <a href="#" className="hero__app-btn" aria-label="App Store">
              <span><img 
    src="https://www.image2url.com/r2/default/images/1782296498702-6e565cc0-d598-472e-a741-7a9b991f3df4.png" 
    alt="Apple Logo"
    style={{ height: '50px', width: 'auto', marginRight: '5px' }} 
  /></span> App Store
            </a>
          </div>

          {/* Trust badges */}
          <div className="hero__trust">
            <span>✅ 500+ xe</span>
            <span>✅ 8 năm kinh nghiệm</span>
            <span>✅ Bảo hiểm toàn chuyến</span>
          </div>
        </div>

        {/* Booking form */}
        <div className="hero__form-wrap card">
          <div className="hero__form-header">
            🗓️ Đặt xe ngay
          </div>
          <form onSubmit={handleBook} className="hero__form" noValidate>
            <div className="form-group">
              <label> Điểm đón *</label>
              <input placeholder="Nhập địa chỉ đón" value={form.pickup} onChange={e => set('pickup', e.target.value)} />
            </div>
            <div className="form-group">
              <label> Điểm đến *</label>
              <input placeholder="Nhập địa chỉ đến" value={form.destination} onChange={e => set('destination', e.target.value)} />
            </div>
            <div className="form-row">
              <div className="form-group">
                <label> Thời gian</label>
                <input type="datetime-local" value={form.datetime} onChange={e => set('datetime', e.target.value)} />
              </div>
              <div className="form-group">
                <label> Loại xe</label>
                <select value={form.carType} onChange={e => set('carType', e.target.value)}>
                  {CAR_TYPES.map(t => <option key={t}>{t}</option>)}
                </select>
              </div>
            </div>
            <div className="form-group">
              <label> Dịch vụ</label>
              <select value={form.service} onChange={e => set('service', e.target.value)}>
                {SERVICE_OPTIONS.map(option => <option key={option}>{option}</option>)}
              </select>
            </div>
            <div className="form-row">
              <div className="form-group">
                <label> Họ tên *</label>
                <input placeholder="Nguyễn Văn A" value={form.name} onChange={e => set('name', e.target.value)} />
              </div>
              <div className="form-group">
                <label> Số điện thoại *</label>
                <input type="tel" placeholder="09xx xxx xxx" value={form.phone} onChange={e => set('phone', e.target.value)} />
              </div>
            </div>

            {quoteNote && (
              <div className="hero__estimate">
                <strong>Nhận báo giá ngay:</strong> {quoteNote}
              </div>
            )}

            <div className="hero__form-actions">
              <button type="button" className="btn btn-outline btn-sm" onClick={handleEstimate}>
                Nhận báo giá
              </button>
              <button type="submit" className="btn btn-primary" disabled={loading}>
                {loading ? '⏳ Đang xử lý...' : ' Đặt xe ngay'}
              </button>
            </div>
          </form>
        </div>
      </div>

      {/* Wave divider */}
      <div className="hero__wave" aria-hidden="true">
        <svg viewBox="0 0 1440 80" preserveAspectRatio="none">
          <path d="M0,40 C360,80 1080,0 1440,40 L1440,80 L0,80 Z" fill="#fff" />
        </svg>
      </div>
    </section>
  );
}
